import pandas as pd     #type:ignore

def analyze_uq_results(filename="csv/uq_results_90W.csv"):
    # Load the results generated by your campaign runner
    df = pd.read_csv(filename)
    
    # Calculate statistics for the primary QoIs 
    qois = ['T_max', 't_melt']
    stats = df[qois].agg(['mean', 'var', 'std', 'min', 'max'])
    
    print("--- STOCHASTIC BASELINE STATISTICS ---")
    print(stats)
    
    # Optional: Check for thermal defects
    # Ti-6Al-4V melting point is 1933.0 K
    melt_count = (df['T_max'] >= 1933.0).sum()
    print(f"\nSamples resulting in melting: {melt_count} / {len(df)}")
    
    return stats

if __name__ == "__main__":
    analyze_uq_results()